import React, { useEffect, useState } from "react";
import axios from "axios";

const Report = () => {
  const [monthlyRevenue, setMonthlyRevenue] = useState([]);
  const [yearlyRevenue, setYearlyRevenue] = useState([]);
  const [topCustomers, setTopCustomers] = useState([]);
  const [roomUsage, setRoomUsage] = useState([]);
  const [viewMode, setViewMode] = useState("monthly");

  const apiBase = "http://localhost:5000/api/report";

  useEffect(() => {
    fetchRevenue();
    fetchTopCustomers();
    fetchRoomUsage();
  }, []);

  const fetchRevenue = async () => {
    try {
      const res = await axios.get(`${apiBase}/revenue`);
      setMonthlyRevenue(res.data.monthly);
      setYearlyRevenue(res.data.yearly);
    } catch (err) {
      console.error(err);
      alert("Lỗi khi tải báo cáo doanh thu");
    }
  };

  const fetchTopCustomers = async () => {
    try {
      const res = await axios.get(`${apiBase}/topcustomer`);
      setTopCustomers(res.data);
    } catch (err) {
      console.error(err);
      alert("Lỗi khi tải top khách hàng");
    }
  };

  const fetchRoomUsage = async () => {
    try {
      const res = await axios.get(`${apiBase}/roomusage`);
      setRoomUsage(res.data);
    } catch (err) {
      console.error(err);
      alert("Lỗi khi tải công suất phòng");
    }
  };

  const renderRevenueTable = () => {
    const data = viewMode === "monthly" ? monthlyRevenue : yearlyRevenue;

    if (data.length === 0) return <p className="p-2">Chưa có dữ liệu</p>;

    return (
      <table className="w-full border border-gray-300 rounded overflow-hidden">
        <thead className="bg-blue-200 text-center">
          <tr>
            {viewMode === "monthly" && <th className="border px-3 py-2">Năm</th>}
            {viewMode === "monthly" && <th className="border px-3 py-2">Tháng</th>}
            <th className="border px-3 py-2">Doanh thu</th>
            {viewMode === "yearly" && <th className="hidden"></th>}
          </tr>
        </thead>
        <tbody>
          {data.map((row, idx) => (
            <tr
              key={idx}
              className={idx % 2 === 0 ? "bg-gray-50 hover:bg-gray-100" : "bg-white hover:bg-gray-100"}
            >
              {viewMode === "monthly" && <td className="border px-3 py-2 text-center">{row.Nam}</td>}
              {viewMode === "monthly" && <td className="border px-3 py-2 text-center">{row.Thang}</td>}
              <td className="border px-3 py-2 text-right">{row.DoanhThu}</td>
            </tr>
          ))}
        </tbody>
      </table>
    );
  };

  const Card = ({ title, children }) => (
    <div className="border rounded shadow-lg p-4 mb-6 bg-white">
      <h2 className="text-lg font-semibold mb-4">{title}</h2>
      {children}
    </div>
  );

  const renderTable = (data, columns, striped = true) => (
    <table className="w-full border border-gray-300 rounded overflow-hidden">
      <thead className="bg-gray-200 text-center">
        <tr>
          {columns.map((col, idx) => (
            <th key={idx} className="border px-3 py-2">{col}</th>
          ))}
        </tr>
      </thead>
      <tbody>
        {data.map((row, idx) => (
          <tr
            key={idx}
            className={
              striped
                ? idx % 2 === 0
                  ? "bg-gray-50 hover:bg-gray-100"
                  : "bg-white hover:bg-gray-100"
                : "hover:bg-gray-100"
            }
          >
            {columns.map((col, cIdx) => (
              <td key={cIdx} className="border px-3 py-2 text-center">
                {row[col] ?? row[col.replace(/\s+/g, "")]}
              </td>
            ))}
          </tr>
        ))}
      </tbody>
    </table>
  );

  return (
    <div className="p-6 bg-gray-50 min-h-screen">
      <h1 className="text-2xl font-bold mb-6 text-center">Báo cáo tổng hợp</h1>

      {/* Doanh thu */}
      <Card title="Doanh thu">
        <div className="mb-4 flex items-center">
          <label className="mr-2 font-semibold">Xem theo:</label>
          <select
            value={viewMode}
            onChange={(e) => setViewMode(e.target.value)}
            className="border rounded px-2 py-1"
          >
            <option value="monthly">Tháng</option>
            <option value="yearly">Năm</option>
          </select>
        </div>
        {renderRevenueTable()}
      </Card>

      {/* Top khách hàng */}
      <Card title="Top khách hàng">
        {topCustomers.length === 0 ? (
          <p>Chưa có dữ liệu</p>
        ) : (
          renderTable(topCustomers, ["MaKH", "HoTen", "SoLanDat", "TongChiTieu"])
        )}
      </Card>

      {/* Công suất phòng */}
      <Card title="Công suất phòng">
        {roomUsage.length === 0 ? (
          <p>Chưa có dữ liệu</p>
        ) : (
          renderTable(roomUsage, ["PhongSo", "SoLanThue"])
        )}
      </Card>
    </div>
  );
};

export default Report;
